export const TRADUCTIONS: Record<Langue, Record<CleTraduction, string>> = { fr, en, es, de }
export const LOCALES: Record<Langue, string> = { fr: 'fr-FR', en: 'en-US', es: 'es-ES', de: 'de-DE' }

export function detecterLangue(locale: string | undefined | null): Langue {
  const code = locale?.toLowerCase().split(/[-_]/)[0]
  return LANGUES.includes(code as Langue) ? (code as Langue) : 'fr'
}

export function resoudreLangue(preference: PreferenceLangue | undefined, localeSysteme: string): Langue {
  return preference && preference !== 'auto' ? preference : detecterLangue(localeSysteme)
}

export function traduire(langue: Langue, cle: CleTraduction, variables: VariablesTraduction = {}): string {
  return TRADUCTIONS[langue][cle].replace(/\{(\w+)\}/g, (_match, nom: string) => String(variables[nom] ?? `{${nom}}`))
}
